import{_ as e,o as a,c as o,ag as n}from"./chunks/framework.DXGyWiRo.js";const d=JSON.parse('{"title":"Tips for Parent Volunteers","description":"","frontmatter":{},"headers":[],"relativePath":"voice-logging/parent-volunteers.md","filePath":"voice-logging/parent-volunteers.md"}'),r={name:"voice-logging/parent-volunteers.md"};function i(l,t,s,u,p,h){return a(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="tips-for-parent-volunteers" tabindex="-1">Tips for Parent Volunteers <a class="header-anchor" href="#tips-for-parent-volunteers" aria-label="Permalink to &quot;Tips for Parent Volunteers&quot;">​</a></h1><p>Thank you for helping log game data. Here is everything you need to know to get started quickly.</p><h2 id="what-you-are-doing" tabindex="-1">What You Are Doing <a class="header-anchor" href="#what-you-are-doing" aria-label="Permalink to &quot;What You Are Doing&quot;">​</a></h2><p>You are describing baseball plays out loud and the app records them automatically. You do not need to know the app — just describe what you see the way you would tell someone about the play.</p><h2 id="getting-set-up" tabindex="-1">Getting Set Up <a class="header-anchor" href="#getting-set-up" aria-label="Permalink to &quot;Getting Set Up&quot;">​</a></h2><ol><li>Install Diamond Analytics on your phone (your coach will send you an invite link)</li><li>Open the app and join your team using the invite link</li><li>On Android: set Google Voice Typing as your default keyboard for best results (Settings → General Management → Keyboard list and default)</li></ol><h2 id="during-the-game" tabindex="-1">During the Game <a class="header-anchor" href="#during-the-game" aria-label="Permalink to &quot;During the Game&quot;">​</a></h2><ol><li>Your coach will start the game session</li><li>Tap <strong>Voice Log</strong> from the Game Hub</li><li><strong>On mobile:</strong> The keyboard appears automatically. Tap the microphone icon on your keyboard, describe the play, then tap the arrow button when done</li><li><strong>On desktop:</strong> Tap the microphone button, speak, done automatically</li></ol><h2 id="what-to-say" tabindex="-1">What to Say <a class="header-anchor" href="#what-to-say" aria-label="Permalink to &quot;What to Say&quot;">​</a></h2><p>Keep it simple — just describe what happened:</p><p><strong>For pitches:</strong> &quot;[Player name] [pitch type] [location] [result]&quot; Example: &quot;Glaros fastball low strike swinging&quot;</p><p><strong>For hits:</strong> &quot;[Player name] [contact] [direction] [result]&quot; Example: &quot;Hupp ground ball to short out&quot;</p><p><strong>For fielding plays:</strong> &quot;[Player name] [position] [ball type] [what happened]&quot; Example: &quot;Dean shortstop ground ball threw to first out&quot;</p><p><strong>For stolen bases:</strong> &quot;[Player name] stole [base] safe&quot; or &quot;[Player name] caught stealing [base]&quot;</p><h2 id="if-the-app-gets-it-wrong" tabindex="-1">If the App Gets It Wrong <a class="header-anchor" href="#if-the-app-gets-it-wrong" aria-label="Permalink to &quot;If the App Gets It Wrong&quot;">​</a></h2><p>After you speak a confirmation card appears. If anything looks wrong:</p><ul><li>Tap <strong>Edit</strong> to fix it manually</li><li>Or tap <strong>Try Again</strong> to re-speak the play</li><li>Tap <strong>Confirm and Save</strong> when it looks right</li></ul><h2 id="you-cannot-break-anything" tabindex="-1">You Cannot Break Anything <a class="header-anchor" href="#you-cannot-break-anything" aria-label="Permalink to &quot;You Cannot Break Anything&quot;">​</a></h2><p>If you make a mistake the coach can correct it later in Data Management. Just do your best — partial data is better than no data.</p>',19)])])}const c=e(r,[["render",i]]);export{d as __pageData,c as default};
